fn ascii_char(b: u8) -> char {
    if (0x20..=0x7e).contains(&b) {
        b as char
    } else {
        '.'
    }
}

fn color_for(byte: u8) -> String {
    // ANSI 256-color foreground: \x1b[38;5;{N}m
    format!("\x1b[38;5;{}m", byte)
}

const ANSI_RESET: &str = "\x1b[0m";

fn token_slot_width(fmt: Format, prefix: bool) -> usize {
    // width INCLUDING trailing space separator
    let prefix_width = if prefix { 2 } else { 0 };
    match fmt {
        Format::Octal => prefix_width + 4 + 1,    // "0o0XXX " = 7
        Format::LowerHex | Format::UpperHex => prefix_width + 2 + 1, // "0xXX " = 5
        Format::Binary => prefix_width + 8 + 1,   // "0bXXXXXXXX " = 11
    }
}

const EMPTY_SLOT_WIDTH: usize = 5;

fn hex_dump(bytes: &[u8], cols: usize, fmt: Format, color: bool, prefix: bool) -> io::Result<()> {
    let stdout = io::stdout();
    let mut out = stdout.lock();

    let total = bytes.len();
    let mut offset: usize = 0;
    let token_w = token_slot_width(fmt, prefix);

    loop {
        let end = std::cmp::min(offset + cols, total);
        let chunk = &bytes[offset..end];

        // header: "0xNNNNNN: "
        write!(out, "0x{:06x}: ", offset)?;

        // byte slots
        for i in 0..cols {
            if i < chunk.len() {
                let b = chunk[i];
                let token = fmt.render(b, prefix);
                if color {
                    write!(out, "{}{}{}", color_for(b), token, ANSI_RESET)?;
                } else {
                    write!(out, "{}", token)?;
                }
                // trailing space separator (width-1 chars of value + 1 space, except just space here)
                write!(out, " ")?;
            } else if chunk.is_empty() {
                // entire empty trailing line: 5-char empty slot per column, NO ASCII
                write!(out, "{}", " ".repeat(EMPTY_SLOT_WIDTH))?;
            } else {
                // empty slot inside a partial chunk: always 5 chars
                write!(out, "{}", " ".repeat(EMPTY_SLOT_WIDTH))?;
            }
            let _ = token_w; // currently unused (placeholder for clarity)
        }

        // ASCII section
        if !chunk.is_empty() {
            for i in 0..cols {
                if i < chunk.len() {
                    let b = chunk[i];
                    let c = ascii_char(b);
                    if color {
                        write!(out, "{}{}{}", color_for(b), c, ANSI_RESET)?;
                    } else {
                        write!(out, "{}", c)?;
                    }
                } else {
                    write!(out, " ")?;
                }
            }
        }

        writeln!(out)?;

        offset += cols;
        if cols == 0 {
            // cols=0 means we must step by 1 to avoid infinite loop,
            // but the slots are 0 (no bytes/ASCII printed in slots, only header).
            offset += 1;
        }
        if offset > total {
            break;
        }
    }

    writeln!(out, "   bytes: {}", total)?;
    Ok(())
}

fn array_dump(bytes: &[u8], cols: usize, arr: Array) -> io::Result<()> {
    let stdout = io::stdout();
    let mut out = stdout.lock();
    let n = bytes.len();

    // Header
    match arr {
        Array::Rust => writeln!(out, "let ARRAY: [u8; {}] = [", n)?,
        Array::C => writeln!(out, "unsigned char ARRAY[{}] = {{", n)?,
        Array::Golang => writeln!(out, "a := [{}]byte{{", n)?,
        Array::Python => writeln!(out, "a = [")?,
        Array::Kotlin => writeln!(out, "val a = byteArrayOf(")?,
        Array::Java => writeln!(out, "byte[] a = new byte[]{{")?,
        Array::Swift => writeln!(out, "let a: [UInt8] = [")?,
        Array::Fsharp => writeln!(out, "let a = [|")?,
    }

    // item-rendering closure
    let item = |b: u8| -> String {
        match arr {
            Array::Fsharp => format!("0x{:02x}uy", b),
            _ => format!("0x{:02x}", b),
        }
    };

    // Separator between items
    let sep = match arr {
        Array::Fsharp => "; ",
        _ => ", ",
    };

    // For Go: every item (including last) gets the separator
    let trailing_on_last = matches!(arr, Array::Golang);

    // Effective cols for wrapping
    let eff_cols = if cols == 0 { 1 } else { cols };

    if n == 0 {
        // empty body
        writeln!(out, "    ")?;
    } else {
        let mut printed = 0;
        for chunk in bytes.chunks(eff_cols) {
            write!(out, "    ")?;
            for (i, b) in chunk.iter().enumerate() {
                let abs = printed + i;
                write!(out, "{}", item(*b))?;
                if abs < n - 1 || trailing_on_last {
                    write!(out, "{}", sep)?;
                }
            }
            writeln!(out)?;
            printed += chunk.len();
        }
        if n % eff_cols == 0 {
            writeln!(out, "    ")?;
        }
    }

    // Footer
    match arr {
        Array::Rust => writeln!(out, "];")?,
        Array::C => writeln!(out, "}};")?,
        Array::Golang => writeln!(out, "}}")?,
        Array::Python => writeln!(out, "]")?,
        Array::Kotlin => writeln!(out, ")")?,
        Array::Java => writeln!(out, "}};")?,
        Array::Swift => writeln!(out, "]")?,
        Array::Fsharp => writeln!(out, "|]")?,
    }

    Ok(())
}

fn func_dump(n: usize, places: usize) -> io::Result<()> {
    let stdout = io::stdout();
    let mut out = stdout.lock();

    for i in 0..n {
        let v = (std::f64::consts::PI * (i as f64) / (2.0 * n as f64)).sin();
        write!(out, "{:.*},", places, v)?;
        if (i + 1) % FUNC_WRAP == 0 {
            writeln!(out)?;
        }
    }
    writeln!(out)?;
    Ok(())
}

fn read_input(file: Option<&String>) -> io::Result<Box<dyn BufRead>> {
    match file {
        Some(path) => {
            let f = std::fs::File::open(path)?;
            Ok(Box::new(io::BufReader::new(f)))
        }
        None => {
            let stdin = io::stdin();
            Ok(Box::new(io::BufReader::new(stdin)))
        }
    }
}

