#[derive(Clone, Copy, Debug)]
enum Format {
    Octal,
    LowerHex,
    UpperHex,
    Binary,
}

impl Format {
    fn from_str(s: &str) -> Option<Self> {
        match s {
            "o" => Some(Format::Octal),
            "x" => Some(Format::LowerHex),
            "X" => Some(Format::UpperHex),
            "b" => Some(Format::Binary),
            _ => None,
        }
    }

    fn render(self, byte: u8, prefix: bool) -> String {
        match self {
            Format::Octal => {
                if prefix {
                    format!("0o{:04o}", byte)
                } else {
                    format!("{:04o}", byte)
                }
            }
            Format::LowerHex => {
                if prefix {
                    format!("0x{:02x}", byte)
                } else {
                    format!("{:02x}", byte)
                }
            }
            Format::UpperHex => {
                if prefix {
                    format!("0x{:02X}", byte)
                } else {
                    format!("{:02X}", byte)
                }
            }
            Format::Binary => {
                if prefix {
                    format!("0b{:08b}", byte)
                } else {
